from typing import Set, List, Optional, Iterable

import numpy as np
from geosat.cloud import rasterization, PointCloud

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from psanp.segmentation.ground.lane_mark import extract_segmentation


class LaneMarkSegmenter(Classifier):
    def __init__(self, gsd=0.05, stage_name: Optional[str] = None):
        super().__init__(stage_name)
        self.gsd = gsd
        self.input_class = "smooth_ground"
        self.output_class = "lane_mark"

    def input_classes(self) -> Set[str]:
        return {self.input_class}

    def output_classes(self) -> Set[str]:
        return {self.output_class}

    @classmethod
    def options(cls) -> List[Option]:
        return [Option("gsd", "precision", type_cast=float, required=True)]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        input_identifier = pipeline_metadata.classification_codes[self.input_class]
        output_identifier = pipeline_metadata.classification_codes[self.output_class]
        projection_image = extract_segmentation.extract_segmentation(
            cloud, input_identifier, k=self.gsd
        )
        image = np.empty(projection_image.image.shape, dtype=cloud.classification.dtype)
        image.fill(input_identifier)
        image[np.where(projection_image.image)] = output_identifier
        rasterization.apply_classification_image(
            cloud, image, self.gsd, mask=cloud.classification == input_identifier
        )

        return (cloud,)
